// // This module implements a 4-bit D flip-flop with reset functionality.
// On the falling edge of the clock, the current value of D should be stored in Q.
// If RST is deasserted (logic 0), all bits of Q should be reset to 1.
module d_ff_rst (
    input CLK,
    input [3:0] D,
    input RST,
    output reg [3:0] Q
);

always @(posedge CLK) begin
    if (RST) begin
        Q <= 4'b0000;
    end else begin
        Q <= D;
    end
end

endmodule

